import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { Button, Input, Space, Card } from "antd";
import { BiPackage, BiTimeFive, BiMoney } from "react-icons/bi";
import { AiOutlineArrowLeft, AiOutlineSave } from "react-icons/ai";
import {
  createPackage,
  getPackage,
  resetState,
  updatePackage,
} from "../../features/package/packageSlicer";

const schema = yup.object().shape({
  name: yup.string().required("Package Name is Required"),
  duration: yup
    .number()
    .positive("Duration must be a positive number")
    .required("Duration is Required"),
  amount: yup
    .number()
    .positive("Amount must be a positive number")
    .required("Amount is Required"),
});

const AddPackage = () => {
  const dispatch = useDispatch();
  const location = useLocation();
  const navigate = useNavigate();
  const packageId = location.pathname.split("/")[3];

  const packageState = useSelector((state) => state.package);
  const { isSuccess, isError, createdPackage, updatedPackage, packageDetails } =
    packageState;

  useEffect(() => {
    if (packageId !== undefined) {
      dispatch(getPackage(packageId));
    } else {
      dispatch(resetState());
    }
  }, [packageId]);

  useEffect(() => {
    if (isSuccess && createdPackage) {
      toast.success("Access Tier Established");
      navigate("/SuperAdmin/List-package");
    }
    if (isSuccess && updatedPackage) {
      toast.success("Tier Specifications Revised");
      navigate("/SuperAdmin/List-package");
    }
    if (isError) {
      toast.error("Registry Synchronization Failed");
    }
  }, [isSuccess, isError]);

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      name: packageDetails?.name || "",
      duration: packageDetails?.duration || "",
      amount: packageDetails?.amount || "",
      createdByUserId: "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      if (packageId !== undefined) {
        const data = { id: packageId, packageData: values };
        dispatch(updatePackage(data));
        dispatch(resetState());
      } else {
        dispatch(createPackage(values));
      }
    },
  });

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (user) {
      formik.setFieldValue("createdByUserId", user._id);
    }
  }, []);

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500 max-w-4xl mx-auto">
      {/* Header Section */}
      <div className="flex justify-between items-end border-b border-gray-100 pb-6">
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">
            {packageId !== undefined
              ? "Revise Tier Specifications"
              : "Establish Access Tier"}
          </h1>
          <p className="text-gray-500 font-medium tracking-tight">
            Subscription Parameter Definition • System Access Control
          </p>
        </div>
        <Button
          type="text"
          icon={<AiOutlineArrowLeft />}
          className="text-gray-400 hover:text-gray-900 font-bold uppercase tracking-tight text-xs"
          onClick={() => navigate("/SuperAdmin/List-package")}
        >
          Back to Registry
        </Button>
      </div>

      <Card className="enterprise-card bg-white p-6">
        <form onSubmit={formik.handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Package Name */}
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
                Tier Designation (Name)
              </label>
              <Input
                prefix={<BiPackage className="text-gray-300" />}
                placeholder="e.g. Enterprise Advanced"
                size="large"
                className="rounded-xl border-gray-100 h-12"
                name="name"
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.name}
              />
              {formik.touched.name && formik.errors.name && (
                <p className="text-red-500 text-[10px] font-bold uppercase tracking-tight">
                  {formik.errors.name}
                </p>
              )}
            </div>

            {/* Package Duration */}
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
                Temporal Constraint (Months)
              </label>
              <Input
                type="number"
                prefix={<BiTimeFive className="text-gray-300" />}
                placeholder="12"
                size="large"
                className="rounded-xl border-gray-100 h-12"
                name="duration"
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.duration}
              />
              {formik.touched.duration && formik.errors.duration && (
                <p className="text-red-500 text-[10px] font-bold uppercase tracking-tight">
                  {formik.errors.duration}
                </p>
              )}
            </div>

            {/* Package Amount */}
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
                Financial Quota (ETB)
              </label>
              <Input
                type="number"
                prefix={<BiMoney className="text-gray-300" />}
                placeholder="5000"
                size="large"
                className="rounded-xl border-gray-100 h-12"
                name="amount"
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.amount}
              />
              {formik.touched.amount && formik.errors.amount && (
                <p className="text-red-500 text-[10px] font-bold uppercase tracking-tight">
                  {formik.errors.amount}
                </p>
              )}
            </div>
          </div>

          <div className="pt-8 border-t border-gray-50 flex justify-end">
            <Button
              type="primary"
              size="large"
              htmlType="submit"
              icon={<AiOutlineSave />}
              className="bg-blue-600 rounded-xl px-12 font-black uppercase tracking-widest text-xs h-12"
            >
              {packageId !== undefined ? "Commit Revisions" : "Authorize Tier"}
            </Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

export default AddPackage;
